import React, { useState, useEffect } from "react";
import { fetchPosts, fetchPicsumPhotos, buildPicsumUrl, randomPicsumUrl, keywordImageUrl } from "../utils/picsum";
import "./Hero.css";

const DEFAULT_HERO = {
  topbar: "Starting at Rs 69,999 | Rs 47,999. Hurry! Offer ends soon.",
  heading: "Invisible Aligners for a dream smile",
  sub: "Book a Scan and avail a free Orthodontist Consult worth ₹1500",
  button: "Book Free Scan",
};

export default function Hero() {
  const [teeth, setTeeth] = useState("");
  const [name, setName] = useState("");
  const [phone, setPhone] = useState("");
  const [consent, setConsent] = useState(false);
  const [heroImage, setHeroImage] = useState(keywordImageUrl(480, 560, 'smile,clear aligners,dental'));
  const [heroText, setHeroText] = useState(DEFAULT_HERO);

  useEffect(() => {
    let active = true;

    Promise.all([fetchPosts(6), fetchPicsumPhotos(1, 10)])
      .then(([postData, imageData]) => {
        if (!active) return;
        if (imageData?.length) {
          setHeroImage(keywordImageUrl(480, 560, 'smile,aligners,dentist'));
        }
        if (postData?.posts?.length) {
          const post = postData.posts[Math.floor(Math.random() * postData.posts.length)];
          const tag = post.tags?.[0] || "special";
          setHeroText({
            topbar: `Starting at Rs 69,999 | ${tag} offer available now`,
            heading: `Invisible Aligners fora dream smiles`,
            sub: `${post.body.slice(0, 80)}...`,
            button: "Book your free scan",
          });
        }
      })
      .catch(() => {
        if (active) {
          setHeroImage(keywordImageUrl(480, 560, 'smile,aligners,dentist'));
        }
      });

    return () => {
      active = false;
    };
  }, []);

  return (
    <section className="hero">
      {/* Top bar */}
      <div className="hero-topbar">{heroText.topbar}</div>

      <div className="hero-container">
        <div className="hero-grid">

          {/* ===== LEFT CONTENT ===== */}
          <div className="hero-left">

            {/* Brand */}
            {/* <div className="hero-brand">
              <span className="brand-whistle">whistle</span>
              <span className="brand-and"> & </span>
              <span className="brand-smile">SMILE</span>
            </div> */}

            {/* Title + Image: side-by-side on mobile, title only on desktop */}
            <div className="hero-title-row">
              <div className="hero-title-text">
                <h1 className="hero-title">
                  {heroText.heading}
                </h1>
                {/* Subtext: mobile pe title ke neeche, image ke baad */}
                <p className="hero-sub hero-sub-mobile">{heroText.sub}</p>
              </div>

              {/* Image: sirf mobile pe dikhegi */}
              <div className="hero-mobile-img">
                <img
                  src={heroImage}
                  alt="Smile transformation"
                  className="hero-img-small image-hover-scale"
                />
              </div>
            </div>

            {/* Subtext: sirf desktop pe */}
            <p className="hero-sub hero-sub-desktop">{heroText.sub}</p>

            {/* Radio */}
            <div className="hero-radio-group">
              <p className="hero-radio-label">
                Do you have Teeth Gaps or Crooked Teeth?
              </p>
              <div className="hero-radios">
                <label className="radio-opt">
                  <input
                    type="radio"
                    name="teeth"
                    value="yes"
                    onChange={() => setTeeth("yes")}
                    checked={teeth === "yes"}
                  />
                  <span>Yes</span>
                </label>
                <label className="radio-opt">
                  <input
                    type="radio"
                    name="teeth"
                    value="no"
                    onChange={() => setTeeth("no")}
                    checked={teeth === "no"}
                  />
                  <span>No</span>
                </label>
              </div>
            </div>

            {/* Form */}
            <div className="hero-form">
              <input
                className="hero-input"
                placeholder="Full Name*"
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
              />
              <input
                className="hero-input"
                placeholder="+91 Mobile number*"
                type="tel"
                value={phone}
                onChange={(e) => setPhone(e.target.value)}
              />
              <button className="hero-btn">{heroText.button}</button>
            </div>

            {/* Consent */}
            <div className="hero-consent">
              <label className="consent-label">
                <input
                  type="checkbox"
                  checked={consent}
                  onChange={() => setConsent(!consent)}
                />
                <span>
                  I hereby consent to receive calls / messages from Whistle and
                  its partners and override DND settings.
                </span>
              </label>
            </div>

            {/* Clove badge */}
            <div className="hero-badge-row">
              <div className="clove-badge">
                <span className="clove-logo">clove</span>
                <span className="clove-sub">dental</span>
              </div>
              <p className="clove-text">
                Book Free Orthodontist Consult at a Clove Dental Clinic.{" "}
                <strong>450+ Clinics near you</strong>
              </p>
              <button className="find-btn">Find Clinic →</button>
            </div>

          </div>

          {/* ===== RIGHT IMAGE (desktop only) ===== */}
          <div className="hero-right">
            <img
              src={heroImage}
              alt="Smile transformation"
              className="hero-img-large image-hover-scale"
            />
          </div>

        </div>
      </div>
    </section>
  );
}
